1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
14	
15	const quotePremium = (items: Item[]): number => {
16	  const base = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
17	  const firstInsurance = base * FIRST_INSURANCE_RATE;
18	  return base + firstInsurance + PROCESSING_FEE;
19	};
20	
21	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
22	  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
23	});
